from langchain_text_splitters import (
    RecursiveCharacterTextSplitter,
)

splitter = RecursiveCharacterTextSplitter(
    chunk_size=500,
    chunk_overlap=50,
    separators=["\n\n", "\n", ". ", " ", ""],
)
chunks = splitter.split_text(document)
print(chunks[0])

records = [
    {
        "id": f"handbook-{i}",
        "text": c,
        "source": "handbook.md",
        "chunk_index": i,
    }
    for i, c in enumerate(chunks)
]
print(records[0]["id"], "->", records[0]["text"][:50])

from langchain_text_splitters import (
    MarkdownHeaderTextSplitter,
    RecursiveCharacterTextSplitter,
)

# 1) split on headings so sections stay intact
head = MarkdownHeaderTextSplitter(
    headers_to_split_on=[("#", "h1"), ("##", "h2")],
)
sections = head.split_text(markdown_doc)

# 2) then size-split inside each section,
#    keeping the heading metadata on every chunk
sizer = RecursiveCharacterTextSplitter.from_tiktoken_encoder(
    chunk_size=300, chunk_overlap=40,
)
chunks = sizer.split_documents(sections)
print(chunks[0].metadata)   # -> {'h1': ..., 'h2': ...}
